SELECT premise, hypothesis, example_type
FROM examples
WHERE example_id = 0;

SELECT metric_name, value, timestamp, model_version
FROM model_performance
WHERE timestamp = (
    SELECT MAX(timestamp)
    FROM model_performance
);

SELECT analysis_type 
FROM analysis_results 
WHERE confidence = (SELECT MAX(confidence) FROM analysis_results);

SELECT COUNT(submission_id) AS submission_count, MAX(timestamp) AS latest_submission
FROM submissions
WHERE submission_type = 'template';

SELECT example_id, premise, hypothesis
FROM examples
WHERE example_id = 0;

SELECT template_type, COUNT(DISTINCT label) AS distinct_labels_count
   FROM templates
   GROUP BY template_type;

SELECT template, template_type, COUNT(*) AS template_count
FROM templates
WHERE template_type = 'relative clause';

SELECT template_id, COUNT(*) AS variable_value_count
FROM variable_values
GROUP BY template_id;
